section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/ai-pairing-decision-tree.json",
  "title": "AI Pairing Decision Tree",
  "type": "object",
  "required": [
    "artefact_id",
    "task_id",
    "stakes",
    "reversibility",
    "novelty",
    "supervision_budget",
    "verdict",
    "rationale",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "task_id": {
      "type": "string",
      "description": "ticket id, issue url, or branch name",
      "minLength": 1
    },
    "stakes": {
      "type": "string",
      "description": "low|medium|high (data loss / customer impact / cost of revert)",
      "minLength": 1
    },
    "reversibility": {
      "type": "string",
      "description": "reversible|partially-reversible|irreversible",
      "minLength": 1
    },
    "novelty": {
      "type": "string",
      "description": "boilerplate|familiar|novel-pattern",
      "minLength": 1
    },
    "supervision_budget": {
      "type": "string",
      "description": "low|medium|high (minutes the dev can spend reviewing AI output)",
      "minLength": 1
    },
    "verdict": {
      "type": "string",
      "description": "solo|ai-pair|full-agent",
      "minLength": 1
    },
    "rationale": {
      "type": "string",
      "description": "one-sentence justification linking the answers to the verdict",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
